INSERT INTO `site_settings` (`id`, `key`, `value`, `created_at`, `updated_at`) VALUES (4, 'brand_copyright_bn', 'কপিরাইট © 2026 [ ব্র্যান্ড]। সমস্ত অধিকার সংরক্ষিত', '2026-04-01 13:07:55', '2026-04-01 13:07:55');
INSERT INTO `site_settings` (`id`, `key`, `value`, `created_at`, `updated_at`) VALUES (5, 'footer_seo_main', '{\"heading\":\"বাংলাদেশের বিশ্বস্ত অনলাইন ক্যাসিনো এবং ক্রিকেট এক্সচেঞ্জ\",\"intro\":\"Babu88 হল বাংলাদেশের প্রধান অনলাইন ক্যাসিনো, মোবাইল এবং ডেস্কটপ ব্যবহারকারীদের জন্য বিভিন্ন ধরনের গেম অফার করে। খেলোয়াড়রা অনলাইনে আসল টাকা জেতার সুযোগ সহ রুলেট, পোকার, ব্যাকার্যাট, ব্ল্যাকজ্যাক এবং এমনকি ক্রিকেট এক্সচেঞ্জ বাজির বিকল্পগুলি উপভোগ করতে পারে। আমাদের প্ল্যাটফর্ম খেলোয়াড়দের জন্য দ্রুত, বিরামহীন গেমপ্লে এবং দুর্দান্ত বোনাস প্রদান করে। আমরা আপনার তথ্য রক্ষা করতে উন্নত এনক্রিপশন প্রযুক্তি ব্যবহার করে নিরাপত্তা এবং নিরাপত্তাকে অগ্রাধিকার দিই, এবং আমাদের গ্রাহক পরিষেবা 24\\/7 উপলব্ধ। বাংলাদেশের সেরা অনলাইন ক্যাসিনো গেমিং এবং ক্রিকেট এক্সচেঞ্জ বেটিং অভিজ্ঞতার জন্য আজই Babu88-এ যোগ দিন।\"}', '2026-04-01 13:07:55', '2026-04-01 13:07:55');
INSERT INTO `site_settings` (`id`, `key`, `value`, `created_at`, `updated_at`) VALUES (6, 'footer_seo_expandable', '{\"section_heading\":\"যেই গেমগুলো পাবেন\",\"columns\":[[{\"heading\":\"স্লট গেম\",\"body\":\"BABU88 অনলাইন স্লট গেমগুলি একটি বড় ড্র। প্লেয়াররা ভিডিও স্লট, ঐতিহ্যবাহী স্লট এবং প্রগতিশীল জ্যাকপট স্লটগুলির একটি আকর্ষণীয় বৈচিত্র্য উপভোগ করতে পারে। জিআইএলআই গেমস এবং প্রাগম্যাটিক প্লে-এর মতো শীর্ষ প্রদানকারীর কাছ থেকে মানি কামিং, সুপার অ্যাস এবং আরও অনেক কিছুর মতো ভক্তদের পছন্দ খুঁজুন।\"},{\"heading\":\"স্পোর্টস ব্যাটিং\",\"body\":\"ক্রীড়া উত্সাহীদের জন্য, BABU88 একটি ব্যাপক অনলাইন স্পোর্টস বেটিং প্ল্যাটফর্ম প্রদান করে। খেলোয়াড়রা ফুটবল, বাস্কেটবল, টেনিস, ক্রিকেট এবং আরও অনেক কিছু সহ বিশ্বের বিভিন্ন ক্রীড়া ইভেন্টে বাজি রাখতে পারে। ক্রীড়া বেটিং বিভাগটি প্রতিযোগিতামূলক প্রতিকূলতা এবং একটি ব্যবহারকারী-বান্ধব ইন্টারফেস, যা খেলোয়াড়দের সুবিধামত তাদের বাজি রাখতে এবং তাদের প্রিয় দল এবং ম্যাচগুলিকে রিয়েল টাইমে ট্র্যাক করতে দেয়। ICC, IPL, T20, BPL, LPL, CPL এবং আরও অনেক বড় টুর্নামেন্টে বাজি ধরতে আমাদের ক্রিকেট এক্সচেঞ্জ ব্যবহার করুন!\"},{\"heading\":\"লাইভ ক্যাসিনো গেম\",\"body\":\"অনলাইন ক্যাসিনো বাংলাদেশ BABU88 আপনাকে গেমের সবচেয়ে বড় স্যুট প্রদান করে যেগুলিতে আকর্ষণীয় গেমপ্লে এবং জেতার পরে দুর্দান্ত পুরস্কার রয়েছে। ইভোলিউশন গেমিং (ইভো গেমিং), সুপার স্পেড গেমিং, প্রাগম্যাটিক প্লে এবং এই ক্যাসিনোর মতো জনপ্রিয় বিকাশকারীরা BABU88-এ উপযোগী।\"}],[{\"heading\":\"BABU88 এ অর্থপ্রদানের বিকল্প\",\"body\":\"সেরা অনলাইন ক্যাসিনো সাইটগুলি অর্থ জমা এবং উত্তোলনের বিভিন্ন উপায় অফার করে। আমরা আমাদের গ্রাহকদের জন্য বিভিন্ন ধরণের অর্থপ্রদানের বিকল্প প্রদান করি, যার মধ্যে নগদ, বিকাশ, স্থানীয় ব্যাঙ্ক স্থানান্তর এবং আরও অনেক কিছুর মতো পেমেন্ট চ্যানেল সহ ই-ওয়ালেট।\"},{\"heading\":\"লাইসেন্স এবং নিরাপত্তা নীতি\",\"body\":\"BABU88 একটি নিরাপদ এবং ন্যায্য গেমিং পরিবেশ বজায় রাখার জন্য কঠোর নীতি এবং প্রবিধান অনুযায়ী কাজ করে। আমরা আমাদের গেমারদের গোপনীয়তা এবং ব্যক্তিগত তথ্য সুরক্ষিত করার জন্য শক্তিশালী নিরাপত্তা ব্যবস্থা রেখেছি। BABU88 দায়িত্বশীল জুয়া খেলার জন্য প্রতিশ্রুতিবদ্ধ এবং আমাদের ব্যবহারকারীদের মধ্যে স্বাস্থ্যকর গেমিং অভ্যাস উন্নীত করার জন্য সরঞ্জাম এবং সংস্থান সরবরাহ করে।\"},{\"heading\":\"শর্তাবলী\",\"body\":\"BABU88 নিয়ম ও শর্তাবলী (T&C) পরিষ্কার এবং সহজবোধ্য, আমাদের প্ল্যাটফর্মের ব্যবহার নিয়ন্ত্রণ করে এমন নিয়ম ও প্রবিধানের রূপরেখা। এই T&Cগুলি অ্যাকাউন্ট পরিচালনা, প্রচার, আমানত, উত্তোলন এবং ব্যাটিং সহ বিভিন্ন দিক কভার করে। একটি মনোরম এবং সঙ্গতিপূর্ণ গেমিং অভিজ্ঞতার নিশ্চয়তা দিতে, খেলোয়াড়দের T&C এর সাথে পরিচিত হওয়া উচিত।\"}],[{\"heading\":\"24\\/7 গ্রাহক সহায়তা\",\"body\":\"BABU88 সার্বক্ষণিক সহায়তার গুরুত্ব বোঝে, এবং তাই, আমাদের গ্রাহক সহায়তা দিনে 24 ঘন্টা, সপ্তাহের 7 দিন উপলব্ধ। নিবন্ধন, সাইন আপ, জমা বা উত্তোলনের জন্য আপনার সাহায্যের প্রয়োজন হোক না কেন, BABU88 গ্রাহক সহায়তা আপনাকে সেবা দিতে প্রস্তুত।\"}]]}', '2026-04-01 13:07:55', '2026-04-12 19:14:48');
